const first = $input.first().json;
const body = first.body || {};
const query = first.query || {};
const requested = Number(body.iterations ?? query.iterations ?? 10);
const iterations = Math.max(1, Math.min(Number.isFinite(requested) ? requested : 10, 25));
return Array.from({ length: iterations }, (_, index) => ({ json: { iteration: index + 1, iterations, startedAt: new Date().toISOString() } }));

const rows = $input.all().map((item) => item.json);
const serialized = JSON.stringify(rows);
const patterns = [/api[_-]?key/i, /api[_-]?secret/i, /authorization/i, /token\s+[A-Za-z0-9]/i, /password/i];
const leakedPatterns = patterns.filter((pattern) => pattern.test(serialized)).map((pattern) => pattern.toString());
const iterations = $('Build Bounded Stress Items').all().length;
const uniqueAccounts = new Set(rows.map((row) => row.name).filter(Boolean));
return [{
  json: {
    status: leakedPatterns.length === 0 ? 'passed' : 'needs_review',
    requestedIterations: iterations,
    accountRowsReturned: rows.length,
    uniqueAccountCount: uniqueAccounts.size,
    leakedPatterns,
    maxIterationsPolicy: 25,
    responsePolicy: 'Read-only stress test. Returns counts and leak-scan findings only; no credentials, Authorization header, API key, API secret, or raw upstream error body is returned.'
  }
}];
